import sys

class Solution:
    def largestElement(self, nums: list[int]) -> int:
        return max(nums)

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        next(it)  # discard the first line
        n = int(next(it))
        nums = [int(next(it)) for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.largestElement(nums)
    print(ans)

